package com.taskmind.backend.specbreakdown.infrastructure.persistence.jpa;
import com.taskmind.backend.specbreakdown.domain.model.*; import jakarta.persistence.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="spec_breakdown_drafts")
public class SpecBreakdownDraftJpaEntity { @Id UUID id; @Version Long version; UUID projectId; UUID ownerUserId; UUID templateId; String title; @Column(columnDefinition="TEXT") String rawSpec; @Column(columnDefinition="TEXT") String richContent; @Column(columnDefinition="TEXT") String candidateTree; @Enumerated(EnumType.STRING) SpecBreakdownStatus status; String fixVersion; String affectedVersion; String sprint; String issueType; String publishKey; Instant materializedAt; Instant createdAt; Instant updatedAt; protected SpecBreakdownDraftJpaEntity(){} static SpecBreakdownDraftJpaEntity from(SpecBreakdownDraft d){ SpecBreakdownDraftJpaEntity e=new SpecBreakdownDraftJpaEntity(); e.id=d.id(); e.version=d.version(); e.projectId=d.projectId(); e.ownerUserId=d.ownerUserId(); e.templateId=d.templateId(); e.title=d.title(); e.rawSpec=d.rawSpec(); e.richContent=d.richContent(); e.candidateTree=d.candidateTree(); e.status=d.status(); e.fixVersion=d.fixVersion(); e.affectedVersion=d.affectedVersion(); e.sprint=d.sprint(); e.issueType=d.issueType(); e.publishKey=d.publishKey(); e.materializedAt=d.materializedAt(); e.createdAt=d.createdAt(); e.updatedAt=d.updatedAt(); return e;} SpecBreakdownDraft toDomain(){ return new SpecBreakdownDraft(id,version,projectId,ownerUserId,templateId,title,rawSpec,richContent,candidateTree,status,fixVersion,affectedVersion,sprint,issueType,publishKey,materializedAt,createdAt,updatedAt);} }
